def count_distinct_subsequences(s: str) -> int:
    n = len(s)

    dp = [0] * (n + 1)
    dp[0] = 1

    last_occurrence = {}

    for i in range(1, n + 1):
        char = s[i - 1]

        dp[i] = 2 * dp[i-1]

        if char in last_occurrence:
            j = last_occurrence[char]
            dp[i] = dp[i] - dp[j]

        last_occurrence[char] = i - 1

    return dp[n]
